309→/// Try to create an OpenAI provider from stored OAuth credentials.
310→fn try_openai_oauth_provider() -> Option<Arc<dyn Provider>> {
311→    let tokens = arcan_provider::oauth::load_tokens("openai").ok()?;
312→    let credential = Arc::new(arcan_provider::oauth::OAuthCredential::openai(tokens));
313→    let model = std::env::var("OPENAI_MODEL").unwrap_or_else(|_| "gpt-4o".to_string());
314→    let config = arcan_provider::openai::OpenAiConfig::from_oauth(credential, model.clone());
315→    tracing::info!(%model, "Provider: OpenAI (OAuth)");
316→    Some(Arc::new(
317→        arcan_provider::openai::OpenAiCompatibleProvider::new(config),
318→    ))
319→}
