509→async fn run_chat(
510→    data_dir: PathBuf,
511→    resolved: &ResolvedConfig,
512→    session: Option<String>,
513→    url: Option<String>,
514→) -> anyhow::Result<()> {
515→    // Ensure daemon is running first to avoid redb lock conflicts.
516→    let base_url = match url {
517→        Some(u) => u,
518→        None => {
519→            daemon::ensure_daemon(
520→                &data_dir,
521→                resolved.port,
522→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
523→                resolved.model.as_deref(),
524→            )
525→            .await?
526→        }
527→    };
528→
529→    // Resolve session via API (no direct journal access).
530→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
531→    tracing::info!(session = %session, "launching TUI");
532→
533→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
534→        tracing::warn!(%error, "failed to persist last_session hint");
535→    }
536→
537→    arcan_tui::run_tui(base_url, session).await
538→}
