540→async fn run_message(
541→    data_dir: PathBuf,
542→    resolved: &ResolvedConfig,
543→    message: String,
544→    session: Option<String>,
545→    url: Option<String>,
546→    json_output: bool,
547→) -> anyhow::Result<()> {
548→    // Ensure daemon is running first.
549→    let base_url = match url {
550→        Some(u) => u,
551→        None => {
552→            daemon::ensure_daemon(
553→                &data_dir,
554→                resolved.port,
555→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
556→                resolved.model.as_deref(),
557→            )
558→            .await?
559→        }
560→    };
561→
562→    // Resolve session via API (no direct journal access).
563→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
564→
565→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
566→        tracing::warn!(%error, "failed to persist last_session hint");
567→    }
568→
569→    let exit_code = cli_run::run_cli(
570→        &base_url,
571→        &session,
572→        &message,
573→        json_output,
574→        resolved.model.as_deref(),
575→    )
576→    .await?;
577→    if exit_code != 0 {
578→        std::process::exit(exit_code);
579→    }
580→    Ok(())
581→}
