583→#[allow(clippy::print_stdout)]
584→fn run_config(data_dir: &Path, action: ConfigAction) -> anyhow::Result<()> {
585→    match action {
586→        ConfigAction::Init => {
587→            let path = config::local_config_path(data_dir);
588→            if path.exists() {
589→                println!("Config file already exists: {}", path.display());
590→            } else {
591→                std::fs::create_dir_all(data_dir)?;
592→                std::fs::write(&path, config::default_config_content())?;
593→                println!("Created config: {}", path.display());
594→            }
595→        }
596→        ConfigAction::Set { key, value } => {
597→            let mut cfg = config::load_config(data_dir);
598→            cfg.set_key(&key, &value)
599→                .map_err(|e| anyhow::anyhow!("{e}"))?;
600→            config::save_config(data_dir, &cfg)?;
601→            println!("{key} = {value}");
602→        }
603→        ConfigAction::Get { key } => {
604→            let cfg = config::load_config(data_dir);
605→            match cfg.get_key(&key) {
606→                Some(value) => println!("{value}"),
607→                None => println!("(not set)"),
608→            }
609→        }
610→        ConfigAction::List => {
611→            let cfg = config::load_config(data_dir);
612→            let content = toml::to_string_pretty(&cfg)
613→                .map_err(|e| anyhow::anyhow!("failed to serialize config: {e}"))?;
614→            if content.trim().is_empty()
615→                || content.trim() == "[defaults]\n\n[agent]"
616→                || content
617→                    .lines()
618→                    .all(|l| l.trim().is_empty() || l.starts_with('['))
619→            {
620→                println!("(no config values set)");
621→                if let Some(path) = config::global_config_path() {
622→                    println!("Global config: {}", path.display());
623→                }
624→                println!(
625→                    "Local config:  {}",
626→                    config::local_config_path(data_dir).display()
627→                );
628→            } else {
629→                print!("{content}");
630→            }
631→        }
632→    }
633→    Ok(())
634→}
