636→#[allow(clippy::print_stdout)]
637→async fn run_status(data_dir: &Path, resolved: &ResolvedConfig) -> anyhow::Result<()> {
638→    println!("Arcan Status");
639→    println!("============");
640→
641→    // Config
642→    println!(
643→        "Provider:   {}",
644→        if resolved.provider.is_empty() {
645→            "(auto-detect)"
646→        } else {
647→            &resolved.provider
648→        }
649→    );
650→    println!(
651→        "Model:      {}",
652→        resolved.model.as_deref().unwrap_or("(provider default)")
653→    );
654→    println!("Port:       {}", resolved.port);
655→    println!("Data dir:   {}", data_dir.display());
656→
657→    // Daemon status
658→    let base_url = format!("http://127.0.0.1:{}", resolved.port);
659→    match daemon::check_existing_pid(data_dir) {
660→        Some(pid) => {
661→            let client = reqwest::Client::builder()
662→                .timeout(std::time::Duration::from_secs(2))
663→                .build()?;
664→            let healthy = matches!(
665→                client.get(format!("{base_url}/health")).send().await,
666→                Ok(resp) if resp.status().is_success()
667→            );
668→            if healthy {
669→                println!("Daemon:     running (PID {pid}, healthy)");
670→            } else {
671→                println!("Daemon:     running (PID {pid}, NOT healthy)");
672→            }
673→        }
674→        None => {
675→            println!("Daemon:     not running");
676→        }
677→    }
678→
679→    // Last session
680→    match read_last_session_hint(data_dir) {
681→        Some(session) => println!("Session:    {session}"),
682→        None => println!("Session:    (none)"),
683→    }
684→
685→    // Config file locations
686→    if let Some(global_path) = config::global_config_path() {
687→        let exists = global_path.exists();
688→        println!(
689→            "Global cfg: {} {}",
690→            global_path.display(),
691→            if exists { "" } else { "(not found)" }
692→        );
693→    }
694→    let local_path = config::local_config_path(data_dir);
695→    let exists = local_path.exists();
696→    println!(
697→        "Local cfg:  {} {}",
698→        local_path.display(),
699→        if exists { "" } else { "(not found)" }
700→    );
701→
702→    Ok(())
703→}
