705→fn run_login(provider: &str, device: bool) -> anyhow::Result<()> {
706→    match provider {
707→        "openai" | "codex" | "openai-codex" => {
708→            if device {
709→                arcan_provider::oauth::device_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
710→            } else {
711→                arcan_provider::oauth::pkce_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
712→            }
713→            Ok(())
714→        }
715→        _ => Err(anyhow::anyhow!(
716→            "Unknown provider '{provider}'. Supported: openai"
717→        )),
718→    }
719→}
