721→#[allow(clippy::print_stderr)]
722→fn run_logout(provider: &str) -> anyhow::Result<()> {
723→    // Normalize provider name for credential lookup.
724→    let normalized = match provider {
725→        "codex" | "openai-codex" => "openai",
726→        other => other,
