733→fn main() -> anyhow::Result<()> {
734→    let cli = Cli::parse();
735→    let data_dir = resolve_data_dir(&cli.data_dir)?;
736→
737→    // Load layered config.
738→    let file_config = config::load_config(&data_dir);
739→
740→    match cli.command {
741→        Some(Command::Serve {
742→            max_iterations,
743→            approval_timeout,
744→        }) => {
745→            // Structured logging to stderr for daemon mode
746→            tracing_subscriber::fmt()
747→                .with_env_filter(EnvFilter::from_default_env())
748→                .init();
749→
750→            let resolved = config::resolve(
751→                &file_config,
752→                cli.provider.as_deref(),
753→                cli.model.as_deref(),
754→                cli.port,
755→                max_iterations,
756→                approval_timeout,
757→            );
758→
759→            run_serve(&data_dir, &resolved)
760→        }
761→        Some(Command::Chat { session, url }) => {
762→            // File-based logging for TUI mode (don't clobber the terminal)
763→            let log_dir = data_dir.join("logs");
764→            std::fs::create_dir_all(&log_dir)?;
765→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
766→            tracing_subscriber::fmt()
767→                .with_writer(file_appender)
768→                .with_env_filter(EnvFilter::from_default_env())
769→                .init();
770→
771→            let resolved = config::resolve(
772→                &file_config,
773→                cli.provider.as_deref(),
774→                cli.model.as_deref(),
775→                cli.port,
776→                None,
777→                None,
778→            );
779→
780→            let runtime = tokio::runtime::Builder::new_multi_thread()
781→                .enable_all()
782→                .build()?;
783→            runtime.block_on(run_chat(data_dir, &resolved, session, url))
784→        }
785→        Some(Command::Login { provider, device }) => run_login(&provider, device),
786→        Some(Command::Logout { provider }) => run_logout(&provider),
787→        Some(Command::Run {
788→            message,
789→            session,
790→            url,
791→            json,
792→        }) => {
793→            // File-based logging for CLI mode (don't clobber stdout)
794→            let log_dir = data_dir.join("logs");
795→            std::fs::create_dir_all(&log_dir)?;
796→            let file_appender = tracing_appender::rolling::never(&log_dir, "run.log");
797→            tracing_subscriber::fmt()
798→                .with_writer(file_appender)
799→                .with_env_filter(EnvFilter::from_default_env())
800→                .init();
801→
802→            let resolved = config::resolve(
803→                &file_config,
804→                cli.provider.as_deref(),
805→                cli.model.as_deref(),
806→                cli.port,
807→                None,
808→                None,
809→            );
810→
811→            let runtime = tokio::runtime::Builder::new_multi_thread()
812→                .enable_all()
813→                .build()?;
814→            runtime.block_on(run_message(
815→                data_dir, &resolved, message, session, url, json,
816→            ))
817→        }
818→        Some(Command::Config { action }) => run_config(&data_dir, action),
819→        Some(Command::Status) => {
820→            let resolved = config::resolve(
821→                &file_config,
822→                cli.provider.as_deref(),
823→                cli.model.as_deref(),
824→                cli.port,
825→                None,
826→                None,
827→            );
828→
829→            let runtime = tokio::runtime::Builder::new_multi_thread()
830→                .enable_all()
831→                .build()?;
832→            runtime.block_on(run_status(&data_dir, &resolved))
833→        }
834→        Some(Command::Stop) => {
835→            let resolved = config::resolve(
836→                &file_config,
837→                cli.provider.as_deref(),
838→                cli.model.as_deref(),
839→                cli.port,
840→                None,
841→                None,
842→            );
843→
844→            let runtime = tokio::runtime::Builder::new_multi_thread()
845→                .enable_all()
846→                .build()?;
847→            runtime.block_on(daemon::stop_daemon(&data_dir, resolved.port))
848→        }
849→        None => {
850→            // Default: launch TUI with auto-daemon (same as `arcan chat`)
851→            let log_dir = data_dir.join("logs");
852→            std::fs::create_dir_all(&log_dir)?;
853→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
854→            tracing_subscriber::fmt()
855→                .with_writer(file_appender)
856→                .with_env_filter(EnvFilter::from_default_env())
857→                .init();
858→
859→            let resolved = config::resolve(
860→                &file_config,
861→                cli.provider.as_deref(),
862→                cli.model.as_deref(),
863→                cli.port,
864→                None,
865→                None,
866→            );
867→
868→            let runtime = tokio::runtime::Builder::new_multi_thread()
869→                .enable_all()
870→                .build()?;
871→            runtime.block_on(run_chat(data_dir, &resolved, None, None))
872→        }
873→    }
874→}
