 15→/// Shared handle for the runtime broadcast sender.
 16→/// Starts as `None` (before the runtime is created) and is filled in
 17→/// once `KernelRuntime::event_sender()` is available.
 18→pub type StreamingSenderHandle = Arc<std::sync::Mutex<Option<broadcast::Sender<EventRecord>>>>;
 19→
 20→#[derive(Clone)]
 21→pub struct ArcanProviderAdapter {
 22→    provider: Arc<dyn Provider>,
 23→    tools: Vec<arcan_core::protocol::ToolDefinition>,
 24→    streaming_sender: StreamingSenderHandle,
 25→}
 26→
 27→impl ArcanProviderAdapter {
 28→    pub fn new(
 29→        provider: Arc<dyn Provider>,
 30→        tools: Vec<arcan_core::protocol::ToolDefinition>,
 31→        streaming_sender: StreamingSenderHandle,
 32→    ) -> Self {
 33→        Self {
 34→            provider,
 35→            tools,
 36→            streaming_sender,
 37→        }
 38→    }
 39→}
 40→
 41→fn to_stop_reason(stop_reason: ArcanStopReason) -> ModelStopReason {
 42→    match stop_reason {
 43→        ArcanStopReason::EndTurn => ModelStopReason::Completed,
 44→        ArcanStopReason::ToolUse => ModelStopReason::ToolCall,
 45→        ArcanStopReason::NeedsUser => ModelStopReason::Cancelled,
 46→        ArcanStopReason::MaxTokens => ModelStopReason::MaxIterations,
 47→        ArcanStopReason::Safety => ModelStopReason::Error,
 48→        ArcanStopReason::Unknown => ModelStopReason::Other("unknown".to_owned()),
 49→    }
 50→}
 51→
 52→#[async_trait]
 53→impl ModelProviderPort for ArcanProviderAdapter {
 54→    async fn complete(
 55→        &self,
 56→        request: ModelCompletionRequest,
 57→    ) -> Result<ModelCompletion, KernelError> {
 58→        let provider_request = ProviderRequest {
 59→            run_id: request.run_id.as_str().to_owned(),
 60→            session_id: request.session_id.as_str().to_owned(),
 61→            iteration: request.step_index + 1,
 62→            messages: vec![ChatMessage::user(request.objective)],
 63→            tools: self.tools.clone(),
 64→            state: AppState::default(),
 65→        };
 66→
 67→        let provider = self.provider.clone();
 68→        let use_streaming = provider.supports_streaming();
 69→        let sender = self
 70→            .streaming_sender
 71→            .lock()
 72→            .unwrap_or_else(std::sync::PoisonError::into_inner)
 73→            .clone();
 74→
 75→        let session_id = request.session_id.clone();
 76→        let branch_id = request.branch_id.clone();
 77→
 78→        // The Arcan Provider trait is synchronous and may use reqwest::blocking,
 79→        // which panics if called directly on a tokio worker thread.
 80→        // Wrap in spawn_blocking to run on a dedicated thread.
 81→        let turn = tokio::task::spawn_blocking(move || {
 82→            if use_streaming {
 83→                if let Some(sender) = sender {
 84→                    let sess = session_id;
 85→                    let branch = branch_id;
 86→                    return provider.complete_streaming(&provider_request, &|text| {
 87→                        let event = EventRecord::new(
 88→                            sess.clone(),
 89→                            branch.clone(),
 90→                            0, // sequence 0 = ephemeral, not persisted
 91→                            EventKind::AssistantTextDelta {
 92→                                delta: text.to_owned(),
 93→                                index: None,
 94→                            },
 95→                        );
 96→                        let _ = sender.send(event);
 97→                    });
 98→                }
 99→            }
100→            provider.complete(&provider_request)
101→        })
102→        .await
103→        .map_err(|join_error: tokio::task::JoinError| {
104→            KernelError::Runtime(format!("provider task panicked: {join_error}"))
105→        })?
106→        .map_err(|error| KernelError::Runtime(error.to_string()))?;
107→
108→        let mut directives = Vec::new();
109→        let mut final_answer = None;
110→        for directive in turn.directives {
111→            match directive {
112→                ArcanDirective::Text { delta } => {
113→                    directives.push(ModelDirective::TextDelta { delta, index: None });
114→                }
115→                ArcanDirective::ToolCall { call } => {
116→                    directives.push(ModelDirective::ToolCall {
117→                        call: ToolCall {
118→                            call_id: call.call_id,
119→                            tool_name: call.tool_name,
120→                            input: call.input,
121→                            requested_capabilities: Vec::new(),
122→                        },
123→                    });
124→                }
125→                ArcanDirective::StatePatch { patch } => {
126→                    directives.push(ModelDirective::Message {
127→                        role: "system".to_owned(),
128→                        content: serde_json::to_string(&patch.patch)
129→                            .unwrap_or_else(|_| "{}".to_owned()),
130→                    });
131→                }
132→                ArcanDirective::FinalAnswer { text } => {
133→                    final_answer = Some(text.clone());
134→                    directives.push(ModelDirective::Message {
135→                        role: "assistant".to_owned(),
136→                        content: text,
137→                    });
138→                }
139→            }
140→        }
141→
142→        let usage = turn.usage.map(|usage| TokenUsage {
143→            prompt_tokens: usage.input_tokens as u32,
144→            completion_tokens: usage.output_tokens as u32,
145→            total_tokens: usage.total() as u32,
146→        });
147→
148→        Ok(ModelCompletion {
149→            provider: self.provider.name().to_owned(),
150→            model: self.provider.name().to_owned(),
151→            directives,
152→            stop_reason: to_stop_reason(turn.stop_reason),
153→            usage,
154→            final_answer,
155→        })
156→    }
157→}
