176→/// Provider implementation for any OpenAI-compatible chat completions API.
177→///
178→/// Supports tool calling via the `tools` parameter with `function` type.
179→/// Works with OpenAI, Ollama, Together, Groq, LM Studio, vLLM, etc.
180→pub struct OpenAiCompatibleProvider {
181→    config: OpenAiConfig,
182→    client: reqwest::blocking::Client,
183→}
184→
185→impl OpenAiCompatibleProvider {
186→    pub fn new(config: OpenAiConfig) -> Self {
187→        let client = reqwest::blocking::Client::builder()
188→            .timeout(std::time::Duration::from_secs(120))
189→            .build()
190→            .unwrap_or_else(|_| reqwest::blocking::Client::new());
191→        Self { config, client }
192→    }
193→
194→    fn build_messages(&self, messages: &[ChatMessage]) -> Vec<ApiMessage> {
195→        messages
196→            .iter()
197→            .map(|msg| {
198→                let (role, tool_call_id) = match msg.role {
199→                    Role::System => ("system", None),
200→                    Role::User => ("user", None),
201→                    Role::Assistant => ("assistant", None),
202→                    Role::Tool => ("tool", msg.tool_call_id.clone()),
203→                };
204→                ApiMessage {
205→                    role: role.to_string(),
206→                    content: Some(msg.content.clone()),
207→                    tool_call_id,
208→                    tool_calls: None,
209→                }
210→            })
211→            .collect()
212→    }
213→
214→    fn convert_tools(&self, tools: &[ToolDefinition]) -> Vec<ApiTool> {
215→        tools
216→            .iter()
217→            .map(|t| ApiTool {
218→                r#type: "function".to_string(),
219→                function: ApiFunction {
220→                    name: t.name.clone(),
221→                    description: t.description.clone(),
222→                    parameters: t.input_schema.clone(),
223→                    strict: Some(true),
224→                },
225→            })
226→            .collect()
227→    }
228→
229→    fn parse_response(&self, response: ApiResponse) -> Result<ModelTurn, CoreError> {
230→        let choice = response
231→            .choices
232→            .into_iter()
233→            .next()
234→            .ok_or_else(|| CoreError::Provider("OpenAI response had no choices".to_string()))?;
235→
236→        let mut directives = Vec::new();
237→
238→        // Handle text content
239→        if let Some(content) = &choice.message.content {
240→            if !content.is_empty() {
241→                directives.push(ModelDirective::Text {
242→                    delta: content.clone(),
243→                });
244→            }
245→        }
246→
247→        // Handle tool calls
248→        if let Some(tool_calls) = &choice.message.tool_calls {
249→            for tc in tool_calls {
250→                let input: Value =
251→                    serde_json::from_str(&tc.function.arguments).unwrap_or_else(|_| json!({}));
252→                directives.push(ModelDirective::ToolCall {
253→                    call: ToolCall {
254→                        call_id: tc.id.clone(),
255→                        tool_name: tc.function.name.clone(),
256→                        input,
257→                    },
258→                });
259→            }
260→        }
261→
262→        let stop_reason = match choice.finish_reason.as_deref() {
263→            Some("stop") => ModelStopReason::EndTurn,
264→            Some("tool_calls") => ModelStopReason::ToolUse,
265→            Some("length") => ModelStopReason::MaxTokens,
266→            Some("content_filter") => ModelStopReason::Safety,
267→            _ => ModelStopReason::Unknown,
268→        };
269→
270→        let usage = response.usage.map(|u| TokenUsage {
271→            input_tokens: u.prompt_tokens,
272→            output_tokens: u.completion_tokens,
273→            cache_read_tokens: 0,
274→            cache_creation_tokens: 0,
275→        });
276→
277→        Ok(ModelTurn {
278→            directives,
279→            stop_reason,
280→            usage,
281→        })
282→    }
283→
284→    /// Execute with retry logic for transient errors (429, 5xx).
285→    /// On 401 Unauthorized, attempts to refresh the credential once before failing.
286→    fn execute_with_retry(
287→        &self,
288→        body: &Value,
289→        url: &str,
290→        max_retries: u32,
291→    ) -> Result<String, CoreError> {
292→        let mut last_error = None;
293→        let base_delay = std::time::Duration::from_millis(200);
294→        let mut refreshed_on_401 = false;
295→
296→        for attempt in 0..=max_retries {
297→            if attempt > 0 {
298→                let delay = base_delay * 2u32.pow(attempt - 1);
299→                std::thread::sleep(delay);
300→            }
301→
302→            let mut request = self
303→                .client
304→                .post(url)
305→                .header("content-type", "application/json");
306→
307→            // Use credential for auth header (supports API keys, OAuth tokens, etc.)
308→            if let Ok(header_value) = self.config.credential.auth_header() {
309→                request = request.header("authorization", header_value);
310→            }
311→
312→            let response = match request.json(body).send() {
313→                Ok(resp) => resp,
314→                Err(e) if e.is_timeout() && attempt < max_retries => {
315→                    last_error = Some(format!("timeout: {e}"));
316→                    continue;
317→                }
318→                Err(e) => return Err(CoreError::Provider(format!("HTTP request failed: {e}"))),
319→            };
320→
321→            let status = response.status();
322→            let response_text = response
323→                .text()
324→                .map_err(|e| CoreError::Provider(format!("failed to read response: {e}")))?;
325→
326→            // On 401, try refreshing the credential once.
327→            if status.as_u16() == 401
328→                && !refreshed_on_401
329→                && self.config.credential.needs_refresh()
330→                && self.config.credential.refresh().is_ok()
331→            {
332→                refreshed_on_401 = true;
333→                continue;
334→            }
335→
336→            // Retry on transient errors
337→            if (status.as_u16() == 429 || status.is_server_error()) && attempt < max_retries {
338→                last_error = Some(format!("{status}: {response_text}"));
339→                continue;
340→            }
341→
342→            if !status.is_success() {
343→                return Err(CoreError::Provider(format!(
344→                    "{} API returned {status}: {response_text}",
345→                    self.config.provider_name
346→                )));
347→            }
348→
349→            return Ok(response_text);
350→        }
351→
352→        Err(CoreError::Provider(format!(
353→            "{} API failed after {} retries: {}",
354→            self.config.provider_name,
355→            max_retries,
356→            last_error.unwrap_or_default()
357→        )))
358→    }
359→}
