361→impl OpenAiCompatibleProvider {
362→    /// Execute a streaming request, calling `on_text` for each text delta.
363→    /// Accumulates the full response and returns the assembled `ModelTurn`.
364→    fn execute_streaming(
365→        &self,
366→        request: &ProviderRequest,
367→        on_text: &dyn Fn(&str),
368→    ) -> Result<ModelTurn, CoreError> {
369→        let api_messages = self.build_messages(&request.messages);
370→        let api_tools = self.convert_tools(&request.tools);
371→
372→        let mut body = serde_json::json!({
373→            "model": self.config.model,
374→            "messages": api_messages,
375→            "max_tokens": self.config.max_tokens,
376→            "stream": true,
377→        });
378→
379→        if !api_tools.is_empty() {
380→            body["tools"] = serde_json::to_value(&api_tools)
381→                .map_err(|e| CoreError::Provider(format!("failed to serialize tools: {e}")))?;
382→        }
383→
384→        let url = format!("{}/v1/chat/completions", self.config.base_url);
385→
386→        let mut http_request = self
387→            .client
388→            .post(&url)
389→            .header("content-type", "application/json");
390→
391→        // Add authorization header from credential (API key or OAuth token)
392→        if let Ok(auth_header) = self.config.credential.auth_header() {
393→            http_request = http_request.header("authorization", auth_header);
394→        }
395→
396→        let response = http_request
397→            .json(&body)
398→            .send()
399→            .map_err(|e| CoreError::Provider(format!("streaming HTTP request failed: {e}")))?;
400→
401→        if !response.status().is_success() {
402→            let status = response.status();
403→            let body_text = response
404→                .text()
405→                .unwrap_or_else(|_| "<unreadable>".to_string());
406→            return Err(CoreError::Provider(format!(
407→                "{} streaming API returned {status}: {body_text}",
408→                self.config.provider_name
409→            )));
410→        }
411→
412→        let reader = std::io::BufReader::new(response);
413→        let mut accumulated_text = String::new();
414→        // tool_calls accumulator: index → (id, name, arguments)
415→        let mut tool_calls: std::collections::BTreeMap<usize, (String, String, String)> =
416→            std::collections::BTreeMap::new();
417→        let mut finish_reason: Option<String> = None;
418→        let mut usage: Option<ApiUsage> = None;
419→
420→        use std::io::BufRead;
421→        for line in reader.lines() {
422→            let line =
423→                line.map_err(|e| CoreError::Provider(format!("streaming read error: {e}")))?;
424→
425→            let Some(data) = line.strip_prefix("data: ") else {
426→                continue;
427→            };
428→
429→            if data == "[DONE]" {
430→                break;
431→            }
432→
433→            let chunk: StreamChunk = match serde_json::from_str(data) {
434→                Ok(c) => c,
435→                Err(_) => continue, // skip unparseable lines
436→            };
437→
438→            if let Some(u) = chunk.usage {
439→                usage = Some(u);
440→            }
441→
442→            for choice in chunk.choices {
443→                if let Some(reason) = choice.finish_reason {
444→                    finish_reason = Some(reason);
445→                }
446→
447→                if let Some(content) = &choice.delta.content {
448→                    if !content.is_empty() {
449→                        on_text(content);
450→                        accumulated_text.push_str(content);
451→                    }
452→                }
453→
454→                if let Some(tcs) = &choice.delta.tool_calls {
455→                    for tc in tcs {
456→                        let entry = tool_calls
457→                            .entry(tc.index)
458→                            .or_insert_with(|| (String::new(), String::new(), String::new()));
459→
460→                        if let Some(ref id) = tc.id {
461→                            entry.0.clone_from(id);
462→                        }
463→                        if let Some(ref func) = tc.function {
464→                            if let Some(ref name) = func.name {
465→                                entry.1.clone_from(name);
466→                            }
467→                            if let Some(ref args) = func.arguments {
468→                                entry.2.push_str(args);
469→                            }
470→                        }
471→                    }
472→                }
473→            }
474→        }
475→
476→        // Build directives from accumulated data
477→        let mut directives = Vec::new();
478→
479→        if !accumulated_text.is_empty() {
480→            directives.push(ModelDirective::Text {
481→                delta: accumulated_text,
482→            });
483→        }
484→
485→        for (_index, (id, name, arguments)) in tool_calls {
486→            let input: serde_json::Value =
487→                serde_json::from_str(&arguments).unwrap_or_else(|_| serde_json::json!({}));
488→            directives.push(ModelDirective::ToolCall {
489→                call: ToolCall {
490→                    call_id: id,
491→                    tool_name: name,
492→                    input,
493→                },
494→            });
495→        }
496→
497→        let stop_reason = match finish_reason.as_deref() {
498→            Some("stop") => ModelStopReason::EndTurn,
499→            Some("tool_calls") => ModelStopReason::ToolUse,
500→            Some("length") => ModelStopReason::MaxTokens,
501→            Some("content_filter") => ModelStopReason::Safety,
502→            _ => ModelStopReason::Unknown,
503→        };
504→
505→        let token_usage = usage.map(|u| TokenUsage {
506→            input_tokens: u.prompt_tokens,
507→            output_tokens: u.completion_tokens,
508→            cache_read_tokens: 0,
509→            cache_creation_tokens: 0,
510→        });
511→
512→        Ok(ModelTurn {
513→            directives,
514→            stop_reason,
515→            usage: token_usage,
516→        })
517→    }
518→}
