520→impl Provider for OpenAiCompatibleProvider {
521→    fn name(&self) -> &str {
522→        &self.config.model
523→    }
524→
525→    fn supports_streaming(&self) -> bool {
526→        self.config.enable_streaming
527→    }
528→
529→    fn complete_streaming(
530→        &self,
531→        request: &ProviderRequest,
532→        on_text: &dyn Fn(&str),
533→    ) -> Result<ModelTurn, CoreError> {
534→        self.execute_streaming(request, on_text)
535→    }
536→
537→    fn complete(&self, request: &ProviderRequest) -> Result<ModelTurn, CoreError> {
538→        let api_messages = self.build_messages(&request.messages);
539→        let api_tools = self.convert_tools(&request.tools);
540→
541→        let mut body = json!({
542→            "model": self.config.model,
543→            "messages": api_messages,
544→            "max_tokens": self.config.max_tokens,
545→        });
546→
547→        if !api_tools.is_empty() {
548→            body["tools"] = serde_json::to_value(&api_tools)
549→                .map_err(|e| CoreError::Provider(format!("failed to serialize tools: {e}")))?;
550→        }
551→
552→        let url = format!("{}/v1/chat/completions", self.config.base_url);
553→        let response_text = self.execute_with_retry(&body, &url, 3)?;
554→
555→        let api_response: ApiResponse = serde_json::from_str(&response_text).map_err(|e| {
556→            CoreError::Provider(format!(
557→                "failed to parse {} response: {e}\nBody: {}",
558→                self.config.provider_name,
559→                &response_text[..response_text.len().min(500)]
560→            ))
561→        })?;
562→
563→        self.parse_response(api_response)
564→    }
565→}
