936→        let response: ApiResponse = serde_json::from_str(json).unwrap();
937→        let tc = response.choices[0].message.tool_calls.as_ref().unwrap();
938→        assert_eq!(tc.len(), 1);
939→        assert_eq!(tc[0].function.name, "get_weather");
940→        assert!(tc[0].function.arguments.contains("Paris"));
941→    }
942→}
