  1→//! Persistent CLI configuration with layered resolution.
  2→//!
  3→//! Resolution order: hardcoded defaults → global config → project-local config → env vars → CLI flags.
  4→
  5→use serde::{Deserialize, Serialize};
  6→use std::collections::HashMap;
  7→use std::path::{Path, PathBuf};
  8→
  9→/// Top-level TOML configuration file structure.
 10→///
 11→/// All fields use `Option<T>` to allow partial configs and clean merging.
 12→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
 13→#[serde(default)]
 14→pub struct ArcanConfig {
 15→    pub defaults: DefaultsConfig,
 16→    #[serde(default, skip_serializing_if = "HashMap::is_empty")]
 17→    pub providers: HashMap<String, ProviderConfig>,
 18→    pub agent: AgentConfig,
 19→}
 20→
 21→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
 22→#[serde(default)]
 23→pub struct DefaultsConfig {
 24→    pub provider: Option<String>,
 25→    pub model: Option<String>,
 26→    pub port: Option<u16>,
 27→}
 28→
 29→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
 30→#[serde(default)]
 31→pub struct ProviderConfig {
 32→    pub model: Option<String>,
 33→    pub base_url: Option<String>,
 34→    pub max_tokens: Option<u32>,
 35→    pub enable_streaming: Option<bool>,
 36→}
 37→
 38→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
 39→#[serde(default)]
 40→pub struct AgentConfig {
 41→    pub max_iterations: Option<u32>,
 42→    pub approval_timeout: Option<u64>,
 43→}
 44→
 45→/// Fully resolved configuration with concrete values (no Options).
 46→#[derive(Debug, Clone)]
 47→#[allow(dead_code)]
 48→pub struct ResolvedConfig {
 49→    pub provider: String,
 50→    pub model: Option<String>,
 51→    pub port: u16,
 52→    pub max_iterations: u32,
 53→    pub approval_timeout: u64,
 54→    pub provider_config: Option<ProviderConfig>,
 55→}
 56→
 57→impl ArcanConfig {
 58→    /// Merge `other` on top of `self`. Non-None values in `other` win.
 59→    pub fn merge(&mut self, other: &ArcanConfig) {
 60→        if other.defaults.provider.is_some() {
 61→            self.defaults.provider.clone_from(&other.defaults.provider);
 62→        }
 63→        if other.defaults.model.is_some() {
 64→            self.defaults.model.clone_from(&other.defaults.model);
 65→        }
 66→        if other.defaults.port.is_some() {
 67→            self.defaults.port = other.defaults.port;
 68→        }
 69→        if other.agent.max_iterations.is_some() {
 70→            self.agent.max_iterations = other.agent.max_iterations;
 71→        }
 72→        if other.agent.approval_timeout.is_some() {
 73→            self.agent.approval_timeout = other.agent.approval_timeout;
 74→        }
 75→        for (name, pc) in &other.providers {
 76→            let entry = self.providers.entry(name.clone()).or_default();
 77→            if pc.model.is_some() {
 78→                entry.model.clone_from(&pc.model);
 79→            }
 80→            if pc.base_url.is_some() {
 81→                entry.base_url.clone_from(&pc.base_url);
 82→            }
 83→            if pc.max_tokens.is_some() {
 84→                entry.max_tokens = pc.max_tokens;
 85→            }
 86→            if pc.enable_streaming.is_some() {
 87→                entry.enable_streaming = pc.enable_streaming;
 88→            }
 89→        }
 90→    }
 91→
 92→    /// Set a key using dotted notation. Shortcut keys:
 93→    /// `provider` → `defaults.provider`, `model` → `defaults.model`, `port` → `defaults.port`.
 94→    pub fn set_key(&mut self, key: &str, value: &str) -> Result<(), String> {
 95→        match key {
 96→            "provider" | "defaults.provider" => {
 97→                self.defaults.provider = Some(value.to_owned());
 98→            }
 99→            "model" | "defaults.model" => {
100→                self.defaults.model = Some(value.to_owned());
101→            }
102→            "port" | "defaults.port" => {
103→                let port: u16 = value
104→                    .parse()
105→                    .map_err(|e| format!("invalid port value: {e}"))?;
106→                self.defaults.port = Some(port);
107→            }
108→            "agent.max_iterations" | "max_iterations" => {
109→                let v: u32 = value
110→                    .parse()
111→                    .map_err(|e| format!("invalid max_iterations: {e}"))?;
112→                self.agent.max_iterations = Some(v);
113→            }
114→            "agent.approval_timeout" | "approval_timeout" => {
115→                let v: u64 = value
116→                    .parse()
117→                    .map_err(|e| format!("invalid approval_timeout: {e}"))?;
118→                self.agent.approval_timeout = Some(v);
119→            }
120→            _ if key.starts_with("providers.") => {
121→                // e.g. providers.ollama.base_url
122→                let rest = &key["providers.".len()..];
123→                let parts: Vec<&str> = rest.splitn(2, '.').collect();
124→                if parts.len() != 2 {
125→                    return Err(format!(
126→                        "invalid provider key: {key} (expected providers.<name>.<field>)"
127→                    ));
128→                }
129→                let provider_name = parts[0];
130→                let field = parts[1];
131→                let entry = self.providers.entry(provider_name.to_owned()).or_default();
132→                match field {
133→                    "model" => entry.model = Some(value.to_owned()),
134→                    "base_url" => entry.base_url = Some(value.to_owned()),
135→                    "max_tokens" => {
136→                        let v: u32 = value
137→                            .parse()
138→                            .map_err(|e| format!("invalid max_tokens: {e}"))?;
139→                        entry.max_tokens = Some(v);
140→                    }
141→                    "enable_streaming" => {
142→                        let v: bool = value
143→                            .parse()
144→                            .map_err(|e| format!("invalid enable_streaming: {e}"))?;
145→                        entry.enable_streaming = Some(v);
146→                    }
147→                    _ => return Err(format!("unknown provider field: {field}")),
148→                }
149→            }
150→            _ => return Err(format!("unknown config key: {key}")),
151→        }
152→        Ok(())
153→    }
154→
155→    /// Get a value by key. Returns None if unset.
156→    pub fn get_key(&self, key: &str) -> Option<String> {
157→        match key {
158→            "provider" | "defaults.provider" => self.defaults.provider.clone(),
159→            "model" | "defaults.model" => self.defaults.model.clone(),
160→            "port" | "defaults.port" => self.defaults.port.map(|p| p.to_string()),
161→            "agent.max_iterations" | "max_iterations" => {
162→                self.agent.max_iterations.map(|v| v.to_string())
163→            }
164→            "agent.approval_timeout" | "approval_timeout" => {
165→                self.agent.approval_timeout.map(|v| v.to_string())
166→            }
167→            _ if key.starts_with("providers.") => {
168→                let rest = &key["providers.".len()..];
169→                let parts: Vec<&str> = rest.splitn(2, '.').collect();
170→                if parts.len() != 2 {
171→                    return None;
172→                }
173→                let pc = self.providers.get(parts[0])?;
174→                match parts[1] {
175→                    "model" => pc.model.clone(),
176→                    "base_url" => pc.base_url.clone(),
177→                    "max_tokens" => pc.max_tokens.map(|v| v.to_string()),
178→                    "enable_streaming" => pc.enable_streaming.map(|v| v.to_string()),
179→                    _ => None,
180→                }
181→            }
182→            _ => None,
183→        }
184→    }
185→}
