187→/// Global config path: `~/.config/arcan/config.toml`
188→pub fn global_config_path() -> Option<PathBuf> {
189→    dirs::config_dir().map(|d| d.join("arcan").join("config.toml"))
190→}
191→
192→/// Project-local config path: `<data_dir>/config.toml`
193→pub fn local_config_path(data_dir: &Path) -> PathBuf {
194→    data_dir.join("config.toml")
195→}
196→
197→/// Load and merge config from global + local files.
198→pub fn load_config(data_dir: &Path) -> ArcanConfig {
199→    let mut config = ArcanConfig::default();
200→
201→    // Layer 1: global config
202→    if let Some(global_path) = global_config_path() {
203→        if let Some(global) = load_config_file(&global_path) {
204→            config.merge(&global);
205→        }
206→    }
207→
208→    // Layer 2: project-local config
209→    let local_path = local_config_path(data_dir);
210→    if let Some(local) = load_config_file(&local_path) {
211→        config.merge(&local);
212→    }
213→
214→    config
215→}
216→
217→/// Load a single TOML config file. Returns None if file doesn't exist or is invalid.
218→fn load_config_file(path: &Path) -> Option<ArcanConfig> {
219→    let content = std::fs::read_to_string(path).ok()?;
220→    toml::from_str(&content).ok()
221→}
222→
223→/// Save config to the project-local config file.
224→pub fn save_config(data_dir: &Path, config: &ArcanConfig) -> anyhow::Result<()> {
225→    let path = local_config_path(data_dir);
226→    std::fs::create_dir_all(data_dir)?;
227→    let content = toml::to_string_pretty(config)
228→        .map_err(|e| anyhow::anyhow!("failed to serialize config: {e}"))?;
229→    std::fs::write(&path, content)?;
230→    Ok(())
231→}
232→
233→/// Resolve the final config by applying env vars and CLI overrides on top.
234→pub fn resolve(
235→    config: &ArcanConfig,
236→    cli_provider: Option<&str>,
237→    cli_model: Option<&str>,
238→    cli_port: Option<u16>,
239→    cli_max_iterations: Option<u32>,
240→    cli_approval_timeout: Option<u64>,
241→) -> ResolvedConfig {
242→    // Provider: CLI > env > config > ""
243→    let provider = cli_provider
244→        .map(String::from)
245→        .or_else(|| std::env::var("ARCAN_PROVIDER").ok())
246→        .or_else(|| config.defaults.provider.clone())
247→        .unwrap_or_default();
248→
249→    // Model: CLI > env > provider-specific config > defaults config > None
250→    let model = cli_model
251→        .map(String::from)
252→        .or_else(|| std::env::var("ARCAN_MODEL").ok())
253→        .or_else(|| {
254→            config
255→                .providers
256→                .get(&provider)
257→                .and_then(|pc| pc.model.clone())
258→        })
259→        .or_else(|| config.defaults.model.clone());
260→
261→    // Port: CLI > env > config > 3000
262→    let port = cli_port
263→        .or_else(|| {
264→            std::env::var("ARCAN_PORT")
265→                .ok()
266→                .and_then(|s| s.parse().ok())
267→        })
268→        .or(config.defaults.port)
269→        .unwrap_or(3000);
270→
271→    // Max iterations: CLI > config > 10
272→    let max_iterations = cli_max_iterations
273→        .or(config.agent.max_iterations)
274→        .unwrap_or(10);
275→
276→    // Approval timeout: CLI > config > 300
277→    let approval_timeout = cli_approval_timeout
278→        .or(config.agent.approval_timeout)
279→        .unwrap_or(300);
280→
281→    // Provider-specific config section
282→    let provider_config = config.providers.get(&provider).cloned();
283→
284→    ResolvedConfig {
285→        provider,
286→        model,
287→        port,
288→        max_iterations,
289→        approval_timeout,
290→        provider_config,
291→    }
292→}
