503→/// Parse a standard OAuth token response into our `OAuthTokenSet`.
504→fn parse_token_response(body: &str, provider: &str) -> Result<OAuthTokenSet, CoreError> {
505→    let resp: TokenResponse = serde_json::from_str(body)
506→        .map_err(|e| CoreError::Auth(format!("invalid token response: {e}")))?;
507→
508→    let now = SystemTime::now()
509→        .duration_since(UNIX_EPOCH)
510→        .map(|d| d.as_secs())
511→        .unwrap_or(0);
512→
513→    Ok(OAuthTokenSet {
514→        access_token: resp.access_token,
515→        refresh_token: resp.refresh_token,
516→        expires_at: now + resp.expires_in.unwrap_or(3600),
517→        provider: provider.to_string(),
518→    })
519→}
520→
521→// ─── Response types ───────────────────────────────────────────────
522→
523→#[derive(Debug, Deserialize)]
524→struct TokenResponse {
525→    access_token: String,
526→    refresh_token: Option<String>,
527→    expires_in: Option<u64>,
528→    #[allow(dead_code)]
529→    token_type: Option<String>,
530→}
531→
532→#[derive(Debug, Deserialize)]
533→struct DeviceCodeResponse {
534→    device_code: String,
535→    user_code: String,
536→    verification_uri: String,
537→    verification_uri_complete: Option<String>,
538→    expires_in: u64,
539→    interval: u64,
540→}
541→
542→#[derive(Debug, Deserialize)]
543→struct OAuthErrorResponse {
544→    error: String,
545→    error_description: Option<String>,
546→}
547→
548→// ─── URL encoding helper ──────────────────────────────────────────
549→
550→mod urlencoding {
551→    pub fn encode(s: &str) -> String {
552→        let mut encoded = String::new();
553→        for byte in s.bytes() {
554→            match byte {
555→                b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => {
556→                    encoded.push(byte as char);
557→                }
558→                _ => {
559→                    encoded.push('%');
560→                    encoded.push_str(&format!("{byte:02X}"));
561→                }
562→            }
563→        }
564→        encoded
565→    }
566→}
