 14→// ─── OpenAI Codex OAuth constants ─────────────────────────────────
 15→
 16→const OPENAI_AUTH_URL: &str = "https://auth.openai.com/authorize";
 17→const OPENAI_TOKEN_URL: &str = "https://auth.openai.com/oauth/token";
 18→const OPENAI_DEVICE_AUTH_URL: &str = "https://auth.openai.com/oauth/device/code";
 19→const OPENAI_CLIENT_ID: &str = "app_scp_BIqDzYAUWMiRFEih7bh0N";
