 23→// ─── Token types ──────────────────────────────────────────────────
 24→
 25→/// Persisted OAuth token set.
 26→#[derive(Debug, Clone, Serialize, Deserialize)]
 27→pub struct OAuthTokenSet {
 28→    pub access_token: String,
 29→    pub refresh_token: Option<String>,
 30→    /// Absolute expiry time (seconds since UNIX epoch).
 31→    pub expires_at: u64,
 32→    pub provider: String,
 33→}
 34→
 35→impl OAuthTokenSet {
 36→    pub fn is_expired(&self) -> bool {
 37→        let now = SystemTime::now()
 38→            .duration_since(UNIX_EPOCH)
 39→            .map(|d| d.as_secs())
 40→            .unwrap_or(0);
 41→        // Treat as expired 60s before actual expiry to avoid edge-case failures.
 42→        now >= self.expires_at.saturating_sub(60)
 43→    }
 44→}
 45→
 46→/// A credential backed by an OAuth token with automatic refresh.
 47→pub struct OAuthCredential {
 48→    tokens: RwLock<OAuthTokenSet>,
 49→    client_id: String,
 50→    token_url: String,
 51→}
 52→
 53→impl fmt::Debug for OAuthCredential {
 54→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 55→        f.debug_struct("OAuthCredential")
 56→            .field("provider", &self.provider_name())
 57→            .field("token_url", &self.token_url)
 58→            .finish()
 59→    }
 60→}
 61→
 62→impl OAuthCredential {
 63→    pub fn new(tokens: OAuthTokenSet, client_id: String, token_url: String) -> Self {
 64→        Self {
 65→            tokens: RwLock::new(tokens),
 66→            client_id,
 67→            token_url,
 68→        }
 69→    }
 70→
 71→    /// Create from a stored token set using OpenAI defaults.
 72→    pub fn openai(tokens: OAuthTokenSet) -> Self {
 73→        Self::new(
 74→            tokens,
 75→            OPENAI_CLIENT_ID.to_string(),
 76→            OPENAI_TOKEN_URL.to_string(),
 77→        )
 78→    }
 79→
 80→    fn provider_name(&self) -> String {
 81→        self.tokens
 82→            .read()
 83→            .map(|t| t.provider.clone())
 84→            .unwrap_or_else(|_| "unknown".to_string())
 85→    }
 86→}
