 88→impl Credential for OAuthCredential {
 89→    fn auth_header(&self) -> Result<String, CoreError> {
 90→        // Auto-refresh if expired.
 91→        if self.needs_refresh() {
 92→            self.refresh()?;
 93→        }
 94→        let tokens = self
 95→            .tokens
 96→            .read()
 97→            .map_err(|e| CoreError::Auth(format!("token lock poisoned: {e}")))?;
 98→        Ok(format!("Bearer {}", tokens.access_token))
 99→    }
100→
101→    fn kind(&self) -> &str {
102→        "oauth"
103→    }
104→
105→    fn needs_refresh(&self) -> bool {
106→        self.tokens.read().map(|t| t.is_expired()).unwrap_or(true)
107→    }
108→
109→    fn refresh(&self) -> Result<(), CoreError> {
110→        let refresh_token = {
111→            let tokens = self
112→                .tokens
113→                .read()
114→                .map_err(|e| CoreError::Auth(format!("token lock poisoned: {e}")))?;
115→            match &tokens.refresh_token {
116→                Some(rt) => rt.clone(),
117→                None => {
118→                    return Err(CoreError::Auth(
119→                        "no refresh token available, re-login required".to_string(),
120→                    ));
121→                }
122→            }
123→        };
124→
125→        let new_tokens = refresh_token_grant(&self.token_url, &self.client_id, &refresh_token)?;
126→
127→        let mut tokens = self
128→            .tokens
129→            .write()
130→            .map_err(|e| CoreError::Auth(format!("token lock poisoned: {e}")))?;
131→
132→        tokens.access_token = new_tokens.access_token;
133→        if let Some(rt) = new_tokens.refresh_token {
134→            tokens.refresh_token = Some(rt);
135→        }
136→        tokens.expires_at = new_tokens.expires_at;
137→
138→        // Persist refreshed tokens.
139→        if let Err(e) = store_tokens(&tokens) {
140→            tracing::warn!(%e, "failed to persist refreshed tokens");
141→        }
142→
143→        Ok(())
144→    }
