147→// ─── Token storage ────────────────────────────────────────────────
148→
149→/// Returns the credentials directory: `~/.arcan/credentials/`.
150→pub fn credentials_dir() -> Result<PathBuf, CoreError> {
151→    let home = dirs::home_dir()
152→        .ok_or_else(|| CoreError::Auth("could not determine home directory".to_string()))?;
153→    Ok(home.join(".arcan").join("credentials"))
154→}
