161→/// Store tokens to `~/.arcan/credentials/<provider>.json`.
162→pub fn store_tokens(tokens: &OAuthTokenSet) -> Result<(), CoreError> {
163→    let dir = credentials_dir()?;
164→    std::fs::create_dir_all(&dir)
165→        .map_err(|e| CoreError::Auth(format!("failed to create credentials dir: {e}")))?;
166→
167→    let path = dir.join(format!("{}.json", tokens.provider));
168→    let json = serde_json::to_string_pretty(tokens)
169→        .map_err(|e| CoreError::Auth(format!("failed to serialize tokens: {e}")))?;
170→
171→    std::fs::write(&path, &json)
172→        .map_err(|e| CoreError::Auth(format!("failed to write credentials: {e}")))?;
173→
174→    // Set file permissions to 0600 (owner read/write only) on Unix.
175→    #[cfg(unix)]
176→    {
177→        use std::os::unix::fs::PermissionsExt;
178→        let perms = std::fs::Permissions::from_mode(0o600);
179→        std::fs::set_permissions(&path, perms)
180→            .map_err(|e| CoreError::Auth(format!("failed to set file permissions: {e}")))?;
181→    }
182→
183→    Ok(())
184→}
