186→/// Load stored tokens for a given provider.
187→pub fn load_tokens(provider: &str) -> Result<OAuthTokenSet, CoreError> {
188→    let path = credential_path(provider)?;
189→    let json = std::fs::read_to_string(&path)
190→        .map_err(|e| CoreError::Auth(format!("no stored credentials for {provider}: {e}")))?;
191→    serde_json::from_str(&json)
192→        .map_err(|e| CoreError::Auth(format!("invalid stored credentials for {provider}: {e}")))
193→}
194→
195→/// Remove stored tokens for a given provider.
196→pub fn remove_tokens(provider: &str) -> Result<(), CoreError> {
197→    let path = credential_path(provider)?;
198→    if path.exists() {
199→        std::fs::remove_file(&path)
200→            .map_err(|e| CoreError::Auth(format!("failed to remove credentials: {e}")))?;
201→    }
202→    Ok(())
203→}
204→
205→/// List providers that have stored credentials.
206→pub fn list_stored_providers() -> Vec<String> {
207→    let Ok(dir) = credentials_dir() else {
208→        return Vec::new();
209→    };
210→    let Ok(entries) = std::fs::read_dir(dir) else {
211→        return Vec::new();
212→    };
213→    entries
214→        .filter_map(std::result::Result::ok)
215→        .filter_map(|e| {
