224→/// Standard OAuth 2.0 refresh_token grant.
225→fn refresh_token_grant(
226→    token_url: &str,
227→    client_id: &str,
228→    refresh_token: &str,
229→) -> Result<OAuthTokenSet, CoreError> {
230→    let client = reqwest::blocking::Client::new();
231→    let resp = client
232→        .post(token_url)
233→        .form(&[
234→            ("grant_type", "refresh_token"),
235→            ("client_id", client_id),
236→            ("refresh_token", refresh_token),
237→        ])
238→        .send()
239→        .map_err(|e| CoreError::Auth(format!("refresh request failed: {e}")))?;
240→
241→    let status = resp.status();
242→    let body = resp
243→        .text()
244→        .map_err(|e| CoreError::Auth(format!("failed to read refresh response: {e}")))?;
245→
246→    if !status.is_success() {
247→        return Err(CoreError::Auth(format!(
248→            "token refresh failed ({status}): {body}"
249→        )));
250→    }
251→
252→    parse_token_response(&body, "openai")
253→}
