255→// ─── PKCE helpers ─────────────────────────────────────────────────
256→
257→/// Generate a random PKCE code verifier (43-128 URL-safe characters).
258→fn generate_code_verifier() -> String {
259→    let mut rng = rand::rng();
260→    let bytes: Vec<u8> = (0..32).map(|_| rng.random::<u8>()).collect();
261→    URL_SAFE_NO_PAD.encode(&bytes)
262→}
263→
264→/// Compute the S256 code challenge from a verifier.
265→fn compute_code_challenge(verifier: &str) -> String {
266→    let hash = Sha256::digest(verifier.as_bytes());
267→    URL_SAFE_NO_PAD.encode(hash)
268→}
