270→// ─── OAuth flows ──────────────────────────────────────────────────
271→
272→/// Run the PKCE Authorization Code flow for OpenAI.
273→///
274→/// 1. Generate PKCE verifier/challenge
275→/// 2. Open browser to authorization URL
276→/// 3. Start local server on port 8769 to receive callback
277→/// 4. Exchange authorization code for tokens
278→/// 5. Store tokens to disk
279→#[allow(clippy::print_stderr)]
280→pub fn pkce_login_openai() -> Result<OAuthTokenSet, CoreError> {
281→    let code_verifier = generate_code_verifier();
282→    let code_challenge = compute_code_challenge(&code_verifier);
283→
284→    // Build authorization URL.
285→    let auth_url = format!(
286→        "{}?response_type=code&client_id={}&redirect_uri={}&scope={}&code_challenge={}&code_challenge_method=S256",
287→        OPENAI_AUTH_URL,
288→        urlencoding::encode(OPENAI_CLIENT_ID),
289→        urlencoding::encode(OPENAI_REDIRECT_URI),
290→        urlencoding::encode(OPENAI_SCOPE),
291→        urlencoding::encode(&code_challenge),
292→    );
293→
294→    eprintln!("Opening browser for OpenAI authentication...");
295→    eprintln!("If the browser doesn't open, visit:\n{auth_url}\n");
296→
297→    // Try to open browser (best-effort).
298→    let _ = open::that(&auth_url);
299→
300→    // Start local callback server.
301→    let listener = std::net::TcpListener::bind("127.0.0.1:8769")
302→        .map_err(|e| CoreError::Auth(format!("failed to bind callback server: {e}")))?;
303→
304→    eprintln!("Waiting for authorization callback on http://127.0.0.1:8769/callback ...");
305→
306→    let code = wait_for_callback(&listener)?;
307→
308→    // Exchange code for tokens.
309→    let client = reqwest::blocking::Client::new();
310→    let resp = client
311→        .post(OPENAI_TOKEN_URL)
312→        .form(&[
313→            ("grant_type", "authorization_code"),
314→            ("client_id", OPENAI_CLIENT_ID),
315→            ("code", code.as_str()),
316→            ("redirect_uri", OPENAI_REDIRECT_URI),
317→            ("code_verifier", code_verifier.as_str()),
318→        ])
319→        .send()
320→        .map_err(|e| CoreError::Auth(format!("token exchange failed: {e}")))?;
321→
322→    let status = resp.status();
323→    let body = resp
324→        .text()
325→        .map_err(|e| CoreError::Auth(format!("failed to read token response: {e}")))?;
326→
327→    if !status.is_success() {
328→        return Err(CoreError::Auth(format!(
329→            "token exchange failed ({status}): {body}"
330→        )));
331→    }
332→
333→    let tokens = parse_token_response(&body, "openai")?;
334→    store_tokens(&tokens)?;
335→
336→    eprintln!("Successfully authenticated with OpenAI!");
337→    Ok(tokens)
338→}
339→
340→/// Run the Device Code flow for OpenAI (headless/SSH environments).
341→///
342→/// 1. Request device code
343→/// 2. Display verification URL and user code
344→/// 3. Poll token endpoint until authorized
345→/// 4. Store tokens to disk
346→#[allow(clippy::print_stderr)]
347→pub fn device_login_openai() -> Result<OAuthTokenSet, CoreError> {
348→    let client = reqwest::blocking::Client::new();
349→
350→    // Step 1: Request device code.
351→    let resp = client
352→        .post(OPENAI_DEVICE_AUTH_URL)
353→        .form(&[("client_id", OPENAI_CLIENT_ID), ("scope", OPENAI_SCOPE)])
354→        .send()
355→        .map_err(|e| CoreError::Auth(format!("device auth request failed: {e}")))?;
356→
357→    let status = resp.status();
358→    let body = resp
359→        .text()
360→        .map_err(|e| CoreError::Auth(format!("failed to read device auth response: {e}")))?;
361→
362→    if !status.is_success() {
363→        return Err(CoreError::Auth(format!(
364→            "device authorization failed ({status}): {body}"
365→        )));
366→    }
367→
368→    let device_resp: DeviceCodeResponse = serde_json::from_str(&body)
369→        .map_err(|e| CoreError::Auth(format!("invalid device auth response: {e}")))?;
370→
371→    // Step 2: Display instructions.
372→    eprintln!("\nTo authenticate, visit: {}", device_resp.verification_uri);
373→    if let Some(ref complete_uri) = device_resp.verification_uri_complete {
374→        eprintln!("Or open: {complete_uri}");
375→    }
376→    eprintln!("Enter code: {}\n", device_resp.user_code);
377→
378→    // Step 3: Poll for token.
379→    let interval = std::time::Duration::from_secs(device_resp.interval.max(5));
380→    let deadline =
381→        std::time::Instant::now() + std::time::Duration::from_secs(device_resp.expires_in.min(900));
382→
383→    loop {
384→        std::thread::sleep(interval);
385→
386→        if std::time::Instant::now() > deadline {
387→            return Err(CoreError::Auth(
388→                "device authorization timed out".to_string(),
389→            ));
390→        }
391→
392→        let resp = client
393→            .post(OPENAI_TOKEN_URL)
394→            .form(&[
395→                ("grant_type", "urn:ietf:params:oauth:grant-type:device_code"),
396→                ("client_id", OPENAI_CLIENT_ID),
397→                ("device_code", &device_resp.device_code),
398→            ])
399→            .send()
400→            .map_err(|e| CoreError::Auth(format!("device token poll failed: {e}")))?;
401→
402→        let status = resp.status();
403→        let body = resp
404→            .text()
405→            .map_err(|e| CoreError::Auth(format!("failed to read poll response: {e}")))?;
406→
407→        if status.is_success() {
408→            let tokens = parse_token_response(&body, "openai")?;
409→            store_tokens(&tokens)?;
410→            eprintln!("Successfully authenticated with OpenAI!");
411→            return Ok(tokens);
412→        }
413→
414→        // Check for specific OAuth error codes.
415→        if let Ok(err_resp) = serde_json::from_str::<OAuthErrorResponse>(&body) {
416→            match err_resp.error.as_str() {
417→                "authorization_pending" => continue,
418→                "slow_down" => {
419→                    // Back off a bit more.
420→                    std::thread::sleep(std::time::Duration::from_secs(5));
421→                    continue;
422→                }
423→                "expired_token" => {
424→                    return Err(CoreError::Auth(
425→                        "device code expired, please try again".to_string(),
426→                    ));
427→                }
428→                "access_denied" => {
429→                    return Err(CoreError::Auth("authorization denied by user".to_string()));
430→                }
431→                _ => {
432→                    return Err(CoreError::Auth(format!(
433→                        "device auth error: {}",
434→                        err_resp.error_description.unwrap_or(err_resp.error)
435→                    )));
436→                }
437→            }
438→        }
439→
440→        return Err(CoreError::Auth(format!(
441→            "unexpected device token response ({status}): {body}"
442→        )));
443→    }
444→}
