446→// ─── Internal helpers ─────────────────────────────────────────────
447→
448→/// Wait for the OAuth callback on a local server, extract the `code` parameter.
449→fn wait_for_callback(listener: &std::net::TcpListener) -> Result<String, CoreError> {
450→    use std::io::{Read, Write};
451→
452→    let (mut stream, _) = listener
453→        .accept()
454→        .map_err(|e| CoreError::Auth(format!("failed to accept callback: {e}")))?;
455→
456→    let mut buf = [0u8; 4096];
457→    let n = stream
458→        .read(&mut buf)
459→        .map_err(|e| CoreError::Auth(format!("failed to read callback request: {e}")))?;
460→    let request = String::from_utf8_lossy(&buf[..n]);
461→
462→    // Extract the request path from "GET /callback?code=...&state=... HTTP/1.1"
463→    let path = request
464→        .lines()
465→        .next()
466→        .and_then(|line| line.split_whitespace().nth(1))
467→        .ok_or_else(|| CoreError::Auth("malformed callback request".to_string()))?;
468→
469→    // Parse the URL to extract the code parameter.
470→    let full_url = format!("http://127.0.0.1:8769{path}");
471→    let parsed = url::Url::parse(&full_url)
472→        .map_err(|e| CoreError::Auth(format!("failed to parse callback URL: {e}")))?;
473→
474→    // Check for error in callback.
475→    if let Some(error) = parsed.query_pairs().find(|(k, _)| k == "error") {
476→        let desc = parsed
477→            .query_pairs()
478→            .find(|(k, _)| k == "error_description")
479→            .map(|(_, v)| v.to_string())
480→            .unwrap_or_default();
481→        // Send error response to browser.
482→        let response = "HTTP/1.1 200 OK\r\nContent-Type: text/html\r\n\r\n<html><body><h1>Authentication Failed</h1><p>You can close this window.</p></body></html>";
483→        let _ = stream.write_all(response.as_bytes());
484→        return Err(CoreError::Auth(format!(
485→            "OAuth error: {} — {desc}",
486→            error.1
487→        )));
488→    }
489→
490→    let code = parsed
491→        .query_pairs()
492→        .find(|(k, _)| k == "code")
493→        .map(|(_, v)| v.to_string())
494→        .ok_or_else(|| CoreError::Auth("no authorization code in callback".to_string()))?;
495→
496→    // Send success response to browser.
497→    let response = "HTTP/1.1 200 OK\r\nContent-Type: text/html\r\n\r\n<html><body><h1>Authenticated!</h1><p>You can close this window and return to the terminal.</p></body></html>";
498→    let _ = stream.write_all(response.as_bytes());
499→
500→    Ok(code)
501→}
