        let now = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs();
        let tokens = OAuthTokenSet {
            access_token: "test".to_string(),
            refresh_token: None,
            expires_at: now + 30, // 30s from now, within 60s buffer.
            provider: "test".to_string(),
        };
        assert!(tokens.is_expired());
