        let verifier = generate_code_verifier();
        let challenge = compute_code_challenge(&verifier);
        // Base64url should not contain +, /, or =.
        assert!(!challenge.contains('+'));
        assert!(!challenge.contains('/'));
        assert!(!challenge.contains('='));
        assert_eq!(challenge.len(), 43); // SHA-256 = 32 bytes → 43 base64url chars.
    }

    #[test]
