        let tokens = parse_token_response(body, "openai").unwrap();
        assert_eq!(tokens.access_token, "at-123");
        assert_eq!(tokens.refresh_token.as_deref(), Some("rt-456"));
        assert_eq!(tokens.provider, "openai");
        assert!(!tokens.is_expired());
    }

