fn main() -> anyhow::Result<()> {
    let cli = Cli::parse();
    let data_dir = resolve_data_dir(&cli.data_dir)?;

    // Load layered config.
    let file_config = config::load_config(&data_dir);

    match cli.command {
        Some(Command::Serve {
            max_iterations,
            approval_timeout,
        }) => {
            // Structured logging to stderr for daemon mode
            tracing_subscriber::fmt()
                .with_env_filter(EnvFilter::from_default_env())
                .init();

            let resolved = config::resolve(
                &file_config,
                cli.provider.as_deref(),
                cli.model.as_deref(),
                cli.port,
                max_iterations,
                approval_timeout,
            );

            run_serve(&data_dir, &resolved)
        }
        Some(Command::Chat { session, url }) => {
            // File-based logging for TUI mode (don't clobber the terminal)
            let log_dir = data_dir.join("logs");
            std::fs::create_dir_all(&log_dir)?;
            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
            tracing_subscriber::fmt()
                .with_writer(file_appender)
                .with_env_filter(EnvFilter::from_default_env())
                .init();

            let resolved = config::resolve(
                &file_config,
                cli.provider.as_deref(),
                cli.model.as_deref(),
                cli.port,
                None,
                None,
            );

            let runtime = tokio::runtime::Builder::new_multi_thread()
                .enable_all()
                .build()?;
            runtime.block_on(run_chat(data_dir, &resolved, session, url))
        }
        Some(Command::Login { provider, device }) => run_login(&provider, device),
        Some(Command::Logout { provider }) => run_logout(&provider),
        Some(Command::Run {
            message,
            session,
